// Extract version from health check (input) and use stored params
// The input comes from Server Healthy? which passes through health check data
const inputData = $input.first().json;

// Health data comes from the health check response
const version = inputData.version || 'unknown';
const environment = inputData.environment || 'unknown';

// Parameters are passed through from Set Parameters via the chain
// We need to access them from the execution context
const params = {
  server_ip: '172.18.0.3',
  server_port: '8080',
  template: 'mle_mbr_asm2d',
  timeout_seconds: 300,
  check_interval_seconds: 60,
  hard_cancel_buffer: 120,
  flow_m3_d: 4000,
  temperature_C: 20,
  COD_mg_L: 350,
  NH4_mg_L: 25,
  TP_mg_L: 8,
  TSS_mg_L: 220
};

// Calculate temperature in Kelvin
const temperature_K = params.temperature_C + 273.15;

// Distribute COD among components (50% S_F, 15% S_A, 35% X_S)
const S_F = params.COD_mg_L * 0.5 * 0.5;  // ~50% of soluble COD
const S_A = params.COD_mg_L * 0.5 * 0.15; // ~15% of soluble COD  
const X_S = params.COD_mg_L * 0.35;       // ~35% particulate

// Distribute TSS (25% X_I, 75% added to X_S)
const X_I = params.TSS_mg_L * 0.25;
const X_S_total = X_S + (params.TSS_mg_L * 0.75 * 0.5); // Adjust for overlap

return {
  json: {
    // Startup message
    startup_message: `Processing with procedure: qsdsan-engine v${version}`,
    server_version: version,
    environment: environment,

    // Pass through parameters
    server_ip: params.server_ip,
    server_port: params.server_port,
    template: params.template,
    timeout_seconds: params.timeout_seconds,
    check_interval_seconds: params.check_interval_seconds,
    hard_cancel_threshold: params.timeout_seconds + params.hard_cancel_buffer,

    // Influent parameters
    flow_m3_d: params.flow_m3_d,
    temperature_K: temperature_K,

    // Calculated concentrations
    concentrations: {
      S_O2: 0,
      S_F: Math.round(S_F * 10) / 10,
      S_A: Math.round(S_A * 10) / 10,
      S_I: 10,
      S_NH4: params.NH4_mg_L,
      S_N2: 0,
      S_NO3: 0,
      S_PO4: params.TP_mg_L,
      S_ALK: 300,
      X_I: Math.round(X_I * 10) / 10,
      X_S: Math.round(X_S_total * 10) / 10,
      X_H: 30,
      X_PAO: 0,
      X_PP: 0,
      X_PHA: 0,
      X_AUT: 0,
      X_MeOH: 0,
      X_MeP: 0,
      H2O: 1000
    },

    // Original user inputs for report
    input_COD: params.COD_mg_L,
    input_NH4: params.NH4_mg_L,
    input_TP: params.TP_mg_L,
    input_TSS: params.TSS_mg_L,
    input_temp_C: params.temperature_C,

    // Tracking
    start_time: Date.now(),
    iteration: 0
  }
};

// Merge job_id with existing data
// Input comes from Submit Simulation which contains the job response
const submitResponse = $input.first().json;

// Rebuild the params since we can't reference other nodes reliably
const params = {
  server_ip: '172.18.0.3',
  server_port: '8080',
  template: 'mle_mbr_asm2d',
  timeout_seconds: 300,
  check_interval_seconds: 60,
  hard_cancel_threshold: 420,
  flow_m3_d: 4000,
  temperature_K: 293.15,
  input_COD: 350,
  input_NH4: 25,
  input_TP: 8,
  input_TSS: 220,
  input_temp_C: 20
};

return {
  json: {
    ...params,
    server_version: 'unknown',
    job_id: submitResponse.job_id,
    job_status: submitResponse.status,
    submit_message: submitResponse.message,
    start_time: Date.now(),
    iteration: 0
  }
};

// Evaluate status and timeout conditions
// Input comes from Check Job Status HTTP request
const statusResponse = $input.first().json;

// Use defaults for timing since we can't reference other nodes
const timeout_seconds = 300;
const hard_cancel_threshold = 420;
const start_time = Date.now() - (statusResponse.elapsed_time_seconds || 0) * 1000;

const elapsed_seconds = statusResponse.elapsed_time_seconds || 0;
const iteration = 1;

// Determine exit condition
let exit_condition = null;
let should_continue = true;
let should_terminate = false;

if (statusResponse.status === 'completed' || statusResponse.status === 'failed') {
  exit_condition = statusResponse.status;
  should_continue = false;
} else if (elapsed_seconds >= hard_cancel_threshold) {
  exit_condition = 'hard_cancel';
  should_continue = false;
  should_terminate = true;
} else if (elapsed_seconds >= timeout_seconds) {
  exit_condition = 'timeout';
  should_continue = false;
}

return {
  json: {
    server_ip: '172.18.0.3',
    server_port: '8080',
    template: 'mle_mbr_asm2d',
    timeout_seconds: timeout_seconds,
    hard_cancel_threshold: hard_cancel_threshold,
    job_id: statusResponse.job_id,
    flow_m3_d: 4000,
    input_COD: 350,
    input_NH4: 25,
    input_TP: 8,
    input_TSS: 220,
    input_temp_C: 20,
    server_version: 'unknown',
    current_status: statusResponse.status,
    elapsed_seconds: elapsed_seconds,
    elapsed_from_api: statusResponse.elapsed_time_seconds,
    iteration: iteration,
    progress_message: `Simulation running... elapsed time: ${elapsed_seconds}s (timeout: ${timeout_seconds}s)`,
    exit_condition: exit_condition,
    should_continue: should_continue,
    should_terminate: should_terminate
  }
};

// Combine all data for report generation
// Input comes from Get Results HTTP request
const resultsResponse = $input.first().json;

// Extract results safely
const results = resultsResponse.results || {};
const performance = results.performance || {};
const effluent = results.effluent || {};
const reactor = results.reactor || {};
const influent = results.influent || {};

// Performance metrics
const cod = performance.cod || {};
const nitrogen = performance.nitrogen || {};
const phosphorus = performance.phosphorus || {};
const tss = performance.tss || {};

// Determine status from results
const exit_condition = resultsResponse.status || 'completed';

// Determine overall assessment
let assessment = 'Incomplete';
if (exit_condition === 'completed') {
  const cod_removal = cod.removal_pct || 0;
  const nh4_eff = effluent.NH4_mg_N_L || 999;

  if (cod_removal > 95 && nh4_eff < 1) {
    assessment = 'Excellent';
  } else if (cod_removal > 85 && nh4_eff < 5) {
    assessment = 'Good';
  } else if (cod_removal > 75) {
    assessment = 'Needs Optimization';
  } else {
    assessment = 'Poor';
  }
}

// Status text
let status_text = exit_condition;
if (status_text === 'hard_cancel') status_text = 'Terminated (hard cancel)';
if (status_text === 'timeout') status_text = 'Timed Out';
if (status_text === 'completed') status_text = 'Completed';
if (status_text === 'failed') status_text = 'Failed';

return {
  json: {
    // Report metadata
    report_date: new Date().toISOString(),
    job_id: resultsResponse.job_id || 'unknown',
    template: 'mle_mbr_asm2d',
    status: status_text,
    elapsed_seconds: 0,
    timeout_setting: 300,
    server_version: 'unknown',
    assessment: assessment,

    // Influent (user inputs)
    influent: {
      flow_m3_d: 4000,
      COD_mg_L: 350,
      TSS_mg_L: 220,
      NH4_mg_L: 25,
      TP_mg_L: 8,
      temperature_C: 20
    },

    // Reactor configuration
    reactor: {
      type: reactor.type || 'N/A',
      V_total_m3: reactor.V_total_m3 || 'N/A',
      HRT_hours: reactor.HRT_hours || 'N/A',
      SRT_days: typeof reactor.SRT_days === 'number' ? reactor.SRT_days.toFixed(1) : 'N/A',
      DO_aerobic: reactor.DO_aerobic_mg_L || 'N/A'
    },

    // Effluent quality
    effluent: {
      COD_mg_L: effluent.COD_mg_L ? effluent.COD_mg_L.toFixed(2) : 'N/A',
      TSS_mg_L: effluent.TSS_mg_L ? effluent.TSS_mg_L.toFixed(2) : 'N/A',
      NH4_mg_L: effluent.NH4_mg_N_L ? effluent.NH4_mg_N_L.toFixed(2) : 'N/A',
      NO3_mg_L: effluent.NO3_mg_N_L ? effluent.NO3_mg_N_L.toFixed(2) : 'N/A',
      PO4_mg_L: effluent.PO4_mg_P_L ? effluent.PO4_mg_P_L.toFixed(2) : 'N/A'
    },

    // Removal efficiencies
    removal: {
      COD_pct: cod.removal_pct ? cod.removal_pct.toFixed(1) : 'N/A',
      TSS_pct: tss.removal_pct ? tss.removal_pct.toFixed(1) : 'N/A',
      NH4_pct: nitrogen.removal?.NH4_removal_pct ? nitrogen.removal.NH4_removal_pct.toFixed(1) : 'N/A',
      TN_pct: nitrogen.removal?.TN_removal_pct ? nitrogen.removal.TN_removal_pct.toFixed(1) : 'N/A',
      TP_pct: phosphorus.removal?.TP_removal_pct ? phosphorus.removal.TP_removal_pct.toFixed(1) : 'N/A'
    },

    // Process performance
    nitrification_pct: nitrogen.removal?.nitrification_efficiency_pct ? nitrogen.removal.nitrification_efficiency_pct.toFixed(1) : 'N/A',
    denitrification_pct: nitrogen.removal?.denitrification_efficiency_pct ? nitrogen.removal.denitrification_efficiency_pct.toFixed(1) : 'N/A',

    // Raw results for reference
    raw_results: resultsResponse
  }
};

// Loop back with updated data for next iteration
const evalData = $input.first().json;

// Update the Store Job ID node data for next iteration
return {
  json: {
    ...evalData
  }
};

// Pass through data after termination
const terminateResponse = $input.first().json;

return {
  json: {
    server_ip: '172.18.0.3',
    server_port: '8080',
    job_id: terminateResponse.job_id || 'unknown',
    termination_response: terminateResponse
  }
};

// Pass through data when no termination needed
const evalData = $input.first().json;

return {
  json: evalData
};
